import{_ as a,o as l,c as i,af as t}from"./chunks/framework.SW4JcFcZ.js";const u=JSON.parse('{"title":"【文档翻译】指南：编写可测试代码（总纲）","description":"","frontmatter":{"title":"【文档翻译】指南：编写可测试代码（总纲）","date":"2023-02-24T12:06:15.000Z","excerpt":"翻译 misko hevery 的 Guide Writing Testable Code","tags":["编写可测试代码"],"categories":["文档翻译"]},"headers":[],"relativePath":"blog/posts/【文档翻译】指南：编写可测试代码（总纲）.md","filePath":"blog/posts/【文档翻译】指南：编写可测试代码（总纲）.md","lastUpdated":null}'),r={name:"blog/posts/【文档翻译】指南：编写可测试代码（总纲）.md"};function o(s,e,n,h,d,_){return l(),i("div",null,[...e[0]||(e[0]=[t('<p><em>为代码编写测试代码是每个软件工程师的美德。</em></p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>很多程序员都有写的代码难以测试的痛苦，这其实说明了代码某些设计的不合理。谷歌的实践中很早就发现了某些代码中不好的设计，正是这些设计阻碍了测试代码的编写。</p><h2 id="正文" tabindex="-1">正文 <a class="header-anchor" href="#正文" aria-label="Permalink to &quot;正文&quot;">​</a></h2><p>为了使谷歌代码保持最佳状态，我们为软件工程师提供以下常规提醒。现在我们很高兴地与全世界分享。</p><p>感谢以下人员的灵感和辛勤工作，使这个指南成为可能：</p><p>同时感谢 Blaine R Southam 制作了 <a href="http://misko.hevery.com/attachments/Guide-Writing%20Testable%20Code.pdf" target="_blank" rel="noreferrer">pdf 书籍</a>。</p><h3 id="缺陷-1-构造函数做了实际工作" tabindex="-1">缺陷 1：构造函数做了实际工作 <a class="header-anchor" href="#缺陷-1-构造函数做了实际工作" aria-label="Permalink to &quot;缺陷 1：构造函数做了实际工作&quot;">​</a></h3><p><strong>危险信号</strong></p><p>以下是构造函数或字段声明中可能出现的警告信号：</p><ul><li>构造函数中出现 new 关键字</li><li>构造函数调用静态方法</li><li>构造函数中出现除了字段初始化之外的任何操作</li><li>构造函数未能降对象未完全初始化（请注意初始化方法）</li><li>构造函数中出现控制流程（例如条件或循环逻辑）</li><li>构造函数中构建复杂对象，而不是使用工厂或构建器</li><li>添加或使用初始化块</li></ul><h3 id="缺陷-2-挖掘合作者类" tabindex="-1">缺陷 2：挖掘合作者类 <a class="header-anchor" href="#缺陷-2-挖掘合作者类" aria-label="Permalink to &quot;缺陷 2：挖掘合作者类&quot;">​</a></h3><p><strong>危险信号</strong></p><ul><li>传递了对象，但从未直接使用（仅用于访问其他对象）</li><li>违反了德米特定律：方法调用链在一个带有多个点（.）的对象图中移动</li><li>可疑的名称：上下文、环境、主体、容器或管理器</li></ul><h3 id="缺陷-3-脆弱的全局状态和单例" tabindex="-1">缺陷 3：脆弱的全局状态和单例 <a class="header-anchor" href="#缺陷-3-脆弱的全局状态和单例" aria-label="Permalink to &quot;缺陷 3：脆弱的全局状态和单例&quot;">​</a></h3><p><strong>危险信号</strong></p><ul><li>添加或使用单例模式</li><li>添加或使用静态字段或静态方法</li><li>添加或使用静态初始化块</li><li>添加或使用注册表</li><li>添加或使用服务定位器</li></ul><h3 id="缺陷-4-类做的太多" tabindex="-1">缺陷 4：类做的太多 <a class="header-anchor" href="#缺陷-4-类做的太多" aria-label="Permalink to &quot;缺陷 4：类做的太多&quot;">​</a></h3><p><strong>危险信号</strong></p><ul><li>总结类的职责中包含&quot;和&quot;这个关键字</li><li>对于团队的新成员来说，阅读和掌握一个类成为挑战</li><li>类具有仅在某些方法中使用的字段</li><li>类具有仅对参数进行操作的静态方法</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><p><a href="http://misko.hevery.com/code-reviewers-guide" target="_blank" rel="noreferrer">《Guide: Writing Testable Code》-- misko.hevery 著</a></p>',22)])])}const c=a(r,[["render",o]]);export{u as __pageData,c as default};
